void _calendarDebugPrint(String? message, {int? wrapWidth}) {
  if (kDebugMode) {
    debugPrint(message, wrapWidth: wrapWidth);
  }
}

typedef QuickAddParse = ({
  DateTime date,
  bool allDay,
  TimeOfDay? start,
  TimeOfDay? end,
  String title,
});

class _QuickAddSheet extends StatefulWidget {
  const _QuickAddSheet({
    required this.parse,
    required this.onSave,
    required this.onOpenFullEditor,
    required this.scaffoldMessengerContext,
  });

  final QuickAddParse? Function(String raw) parse;
  final Future<void> Function(QuickAddParse parsed) onSave;
  final VoidCallback onOpenFullEditor;
  final BuildContext scaffoldMessengerContext;

  @override
  State<_QuickAddSheet> createState() => _QuickAddSheetState();
}

class _QuickAddSheetState extends State<_QuickAddSheet> {
  final TextEditingController _textCtrl = TextEditingController();
  final FocusNode _focusNode = FocusNode();
  final ScrollController _scrollCtrl = ScrollController();
  String? _error;
  bool _submitting = false;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_requestInitialFocus());
    });
  }

  @override
  void dispose() {
    _focusNode.dispose();
    _textCtrl.dispose();
    _scrollCtrl.dispose();
    super.dispose();
  }

  Future<void> _requestInitialFocus() async {
    if (!mounted) return;
    _focusNode.requestFocus();
  }

  void _showSnackBar(SnackBar snackBar) {
    final messenger = ScaffoldMessenger.maybeOf(
      widget.scaffoldMessengerContext,
    );
    messenger?.showSnackBar(snackBar);
  }

  Future<void> _handleSubmit() async {
    if (_submitting) return;

    final parsed = widget.parse(_textCtrl.text);
    if (parsed == null) {
      setState(() {
        _error = 'Please enter a description.';
      });
      return;
    }

    setState(() {
      _error = null;
      _submitting = true;
    });

    try {
      await widget.onSave(parsed);
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint('[QuickAdd] Failed to save note: $e');
        _calendarDebugPrint('$st');
      }
      if (!mounted) return;
      setState(() {
        _submitting = false;
      });
      _showSnackBar(
        SnackBar(
          content: Text('Failed to save note: $e'),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (!mounted) return;
    Navigator.of(context).pop();
    _showSnackBar(
      SnackBar(
        content: Text('Added "${parsed.title}"'),
        backgroundColor: const Color(0xFF1E1E1E),
      ),
    );
  }

  void _handleOpenFullEditor() {
    Navigator.of(context).pop();
    widget.onOpenFullEditor();
  }

  @override
  Widget build(BuildContext context) {
    return KemeticKeyboardRevealScope(
      enabled: false,
      child: AnimatedPadding(
        duration: const Duration(milliseconds: 150),
        curve: Curves.easeOut,
        padding: EdgeInsets.only(
          bottom: MediaQuery.viewInsetsOf(context).bottom,
        ),
        child: SafeArea(
          top: false,
          child: SingleChildScrollView(
            controller: _scrollCtrl,
            padding: const EdgeInsets.fromLTRB(16, 16, 16, 12),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Text(
                  'Quick add (natural language)',
                  style: TextStyle(
                    color: Colors.white,
                    fontSize: 16,
                    fontWeight: FontWeight.w600,
                  ),
                ),
                const SizedBox(height: 8),
                TextField(
                  controller: _textCtrl,
                  scrollPadding: keyboardManagedTextFieldScrollPadding,
                  autofocus: false,
                  focusNode: _focusNode,
                  style: const TextStyle(color: Colors.white),
                  decoration: InputDecoration(
                    hintText: 'e.g., “Fri 3pm-4pm coffee with Amara”',
                    hintStyle: const TextStyle(color: Colors.white54),
                    filled: true,
                    fillColor: const Color(0xFF111111),
                    border: OutlineInputBorder(
                      borderRadius: BorderRadius.circular(12),
                      borderSide: const BorderSide(color: Colors.white24),
                    ),
                  ),
                  minLines: 1,
                  maxLines: 3,
                  onSubmitted: (_) => _handleSubmit(),
                ),
                if (_error != null) ...[
                  const SizedBox(height: 8),
                  Text(
                    _error!,
                    style: const TextStyle(color: Colors.redAccent),
                  ),
                ],
                const SizedBox(height: 12),
                Row(
                  children: [
                    Expanded(
                      child: ElevatedButton(
                        style: ElevatedButton.styleFrom(
                          backgroundColor: KemeticGold.base,
                          foregroundColor: Colors.black,
                        ),
                        onPressed: _submitting ? null : _handleSubmit,
                        child: const Text('Quick add'),
                      ),
                    ),
                    const SizedBox(width: 8),
                    TextButton(
                      onPressed: _submitting ? null : _handleOpenFullEditor,
                      child: KemeticGold.text(
                        'Open full editor',
                        style: const TextStyle(fontWeight: FontWeight.w600),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

