String _maatFlowTemplateDurationLabel(_MaatFlowTemplate template) {
  switch (template.kind) {
    case _MaatFlowTemplateKind.trackSky:
      return 'Ongoing';
    case _MaatFlowTemplateKind.moonReturn:
      return 'Ongoing · ~2/month';
    case _MaatFlowTemplateKind.theWag:
      return 'Annual · Month 1';
    case _MaatFlowTemplateKind.decanWatch:
      return 'Ongoing · ~1 / 10 days';
    case _MaatFlowTemplateKind.daysOutsideTheYear:
      return 'Annual · 7 days';
    case _MaatFlowTemplateKind.theOpenHand:
    case _MaatFlowTemplateKind.theDjed:
      return '30 days · 9 sittings';
    case _MaatFlowTemplateKind.dawnHouseRite:
    case _MaatFlowTemplateKind.eveningThresholdRite:
      return '30 days';
    case _MaatFlowTemplateKind.theWeighing:
    case _MaatFlowTemplateKind.theTending:
    case _MaatFlowTemplateKind.keptWord:
    case _MaatFlowTemplateKind.theCourse:
      return '30 days · 9 sittings';
    case _MaatFlowTemplateKind.offeringTable:
      return '30 days · daily';
    case _MaatFlowTemplateKind.sequence:
      return '${template.days.isEmpty ? 10 : template.days.length} days';
  }
}

/* ─────────────────────────── CALENDAR PAGE (flows + notes) ─────────────────────────── */

final Map<String, GlobalKey> _calendarMonthKeys = <String, GlobalKey>{};
final Map<String, GlobalKey> _calendarMonthHeaderKeys = <String, GlobalKey>{};

GlobalKey keyForMonth(int ky, int km) {
  final id = 'y${ky}m$km';
  return _calendarMonthKeys.putIfAbsent(
    id,
    () => GlobalKey(debugLabel: 'calendar_month_$id'),
  );
}

GlobalKey keyForMonthHeader(int ky, int km) {
  final id = 'y${ky}m$km';
  return _calendarMonthHeaderKeys.putIfAbsent(
    id,
    () => GlobalKey(debugLabel: 'calendar_month_header_$id'),
  );
}

enum _CalendarDetachedLaunchAction {
  quickAdd,
  sharedCalendars,
  flowStudio,
  myFlows,
  search,
}

class CalendarPage extends StatefulWidget {
  final int? initialFlowIdToEdit;
  final bool openMyFlowsOnLaunch;

  CalendarPage({
    Key? key,
    this.initialFlowIdToEdit,
    this.openMyFlowsOnLaunch = false,
  }) : super(key: key ?? CalendarPage.globalKey);

  // Global key for accessing calendar state from other pages
  static final GlobalKey<CalendarPageState> globalKey =
      GlobalKey<CalendarPageState>();
  static _CalendarDetachedLaunchAction? _pendingDetachedLaunchAction;
  static ({int ky, int km, int kd})? _pendingDetachedSearchDay;
  static bool _detachedCalendarOverlayRestoreInFlight = false;
  static bool _detachedSharedCalendarsSheetOpenOrOpening = false;
  static bool _detachedFlowStudioSheetOpenOrOpening = false;
  static bool _detachedQuickAddSheetOpenOrOpening = false;
  static String? _lastDetachedCalendarOverlayRestoreKey;

  static CalendarPageState? get _mountedState {
    final state = globalKey.currentState;
    if (state == null || !state.mounted) return null;
    return state;
  }

  static bool get hasMountedHost => _mountedState != null;

  static Future<void> dismissMountedReflectionPromptIfAny() async {
    final state = _mountedState;
    if (state == null) return;
    await state._dismissReflectionPrompt();
  }

  static bool _isRootRouteLocation(String location) {
    final uri = Uri.tryParse(location.trim());
    return uri == null || uri.path.isEmpty || uri.path == '/';
  }

  static bool _isLibraryRouteLocation(String location) {
    final uri = Uri.tryParse(location.trim());
    final path = uri?.path ?? location.trim();
    return path == '/nodes' || path.startsWith('/nodes/');
  }

  static String _currentRouteLocationForContext(BuildContext context) {
    try {
      final location = GoRouterState.of(context).uri.toString().trim();
      if (location.isNotEmpty) return location;
    } catch (_) {
      // Contexts from popup/menu routes may not carry a GoRouterState.
    }

    try {
      final location = GoRouter.of(
        context,
      ).routerDelegate.currentConfiguration.uri.toString().trim();
      if (location.isNotEmpty) return location;
    } catch (_) {
      // Fall through to the calendar root.
    }

    return '/';
  }

  static bool _shouldUseMountedCalendarHost(BuildContext context) {
    final state = _mountedState;
    if (state == null || !state.mounted) return false;
    return _isRootRouteLocation(_currentRouteLocationForContext(context));
  }

  static CalendarPageState? _mountedCalendarHostForContext(
    BuildContext context,
  ) {
    final state = _mountedState;
    if (state == null || !state.mounted) return null;
    if (!_isRootRouteLocation(_currentRouteLocationForContext(context))) {
      return null;
    }
    return state;
  }

  static List<String> _stringListFromRestorationValue(Object? raw) {
    if (raw is! Iterable) return const <String>[];
    return raw
        .map((value) => value.toString().trim())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
  }

  static Map<String, dynamic>? _restorableCalendarOverlayFromStack(
    List<Map<String, dynamic>> stack,
  ) {
    for (final entry in stack.reversed) {
      final kind = (entry['kind'] as String?)?.trim();
      if (kind == _kCalendarOverlayKindSharedCalendars ||
          kind == _kCalendarOverlayKindFlowStudio) {
        return Map<String, dynamic>.from(entry);
      }
      if (kind == _kCalendarOverlayKindEventDetail) {
        final parentRoute = (entry['parentRoute'] as String?)?.trim();
        final parentSurface = (entry['parentSurface'] as String?)?.trim();
        final isRootParentRoute =
            parentRoute == null ||
            parentRoute.isEmpty ||
            _isRootRouteLocation(parentRoute);
        final isRootParentSurface =
            parentSurface == null ||
            parentSurface.isEmpty ||
            parentSurface == _kCalendarParentSurfaceRoot;
        if (isRootParentRoute && isRootParentSurface) {
          return Map<String, dynamic>.from(entry);
        }
      }
    }
    return null;
  }

  static String? restorableOverlayParentRouteFromStack(
    List<Map<String, dynamic>> stack,
  ) {
    final overlay = _restorableCalendarOverlayFromStack(stack);
    final parentRoute = (overlay?['parentRoute'] as String?)?.trim();
    if (parentRoute == null ||
        parentRoute.isEmpty ||
        _isRootRouteLocation(parentRoute) ||
        _isLibraryRouteLocation(parentRoute)) {
      return null;
    }
    return parentRoute;
  }

  static String _parentSurfaceForRoute(String parentRoute) {
    final uri = Uri.tryParse(parentRoute.trim());
    final path = uri?.path ?? parentRoute.trim();
    if (path.isEmpty || path == '/') return _kCalendarParentSurfaceRoot;
    if (path.startsWith('/profile/')) return _kProfileParentSurface;
    if (path == '/rhythm/today') return _kPlannerTodayParentSurface;
    if (path.startsWith('/rhythm/')) return _kPlannerParentSurface;
    return _kRouteParentSurface;
  }

  static String _calendarOverlayRestoreSurfaceKey(
    Map<String, dynamic> overlay,
  ) {
    final kind = (overlay['kind'] as String?)?.trim() ?? '';
    final parentRoute = (overlay['parentRoute'] as String?)?.trim() ?? '/';
    final parentSurface = (overlay['parentSurface'] as String?)?.trim() ?? '';
    return '${RestorationCoordinator.calendarOverlayStackSurface}|'
        '$kind|$parentRoute|$parentSurface|${overlay['updatedAtMs']}|'
        '${overlay['mode']}|${overlay['templateKey']}|'
        '${overlay['initialFlowId']}|${overlay['editFlowId']}|'
        '${overlay['identityType']}|${overlay['identityValue']}';
  }

  static Future<void> waitForInitialCalendarRestorationToSettle({
    Duration timeout = const Duration(milliseconds: 3600),
  }) async {
    final snapshot = await RestorationCoordinator.instance.readBestSnapshot(
      includeRemote: Supabase.instance.client.auth.currentSession != null,
    );
    final savedDayView = snapshot.snapshot?.dayView;
    final overlay = _restorableCalendarOverlayFromStack(
      snapshot.snapshot?.overlayStack ?? const <Map<String, dynamic>>[],
    );
    final shouldWaitForDayView =
        savedDayView != null &&
        savedDayView.isOpen &&
        RestorationCoordinator.instance.canRestoreSurface(
          RestorationCoordinator.calendarDayViewSurface,
          requireRootTarget: true,
        );
    final overlayKey = overlay == null
        ? null
        : _calendarOverlayRestoreSurfaceKey(overlay);
    final parentRoute = (overlay?['parentRoute'] as String?)?.trim();
    final shouldWaitForRootOverlay =
        overlay != null &&
        (parentRoute == null ||
            parentRoute.isEmpty ||
            _isRootRouteLocation(parentRoute)) &&
        overlayKey != null &&
        RestorationCoordinator.instance.canRestoreSurface(
          overlayKey,
          requireRootTarget: true,
        );
    final shouldWaitForDetachedOverlay =
        overlay != null &&
        parentRoute != null &&
        parentRoute.isNotEmpty &&
        !_isRootRouteLocation(parentRoute) &&
        overlayKey != null &&
        RestorationCoordinator.instance.canRestoreSurface(overlayKey);

    if (!shouldWaitForDayView &&
        !shouldWaitForRootOverlay &&
        !shouldWaitForDetachedOverlay) {
      return;
    }

    final overlayRestoreKey = overlayKey ?? '';
    final deadline = DateTime.now().add(timeout);
    while (DateTime.now().isBefore(deadline)) {
      final state = _mountedState;
      final dayViewSettled =
          !shouldWaitForDayView ||
          state == null ||
          state._persistentDayViewRestoreAttempted;
      final rootOverlaySettled =
          !shouldWaitForRootOverlay ||
          state == null ||
          state._calendarOverlayRestorePresentationStarted ||
          !RestorationCoordinator.instance.canRestoreSurface(
            overlayRestoreKey,
            requireRootTarget: true,
          );
      final detachedOverlaySettled =
          !shouldWaitForDetachedOverlay ||
          _detachedSharedCalendarsSheetOpenOrOpening ||
          _detachedFlowStudioSheetOpenOrOpening ||
          !RestorationCoordinator.instance.canRestoreSurface(overlayRestoreKey);

      if (dayViewSettled && rootOverlaySettled && detachedOverlaySettled) {
        return;
      }
      await Future<void>.delayed(const Duration(milliseconds: 80));
    }
  }

  static Future<void> _saveDetachedCalendarOverlayState({
    required String parentRoute,
    required String kind,
    required Map<String, dynamic> state,
  }) async {
    final normalizedParentRoute =
        parentRoute.trim().isEmpty || _isLibraryRouteLocation(parentRoute)
        ? '/'
        : parentRoute.trim();
    await RestorationCoordinator.instance.recordRouteLocationWithOverlayStack(
      normalizedParentRoute,
      <Map<String, dynamic>>[
        <String, dynamic>{
          'kind': kind.trim(),
          'parentRoute': normalizedParentRoute,
          'parentSurface': _parentSurfaceForRoute(normalizedParentRoute),
          'updatedAtMs': DateTime.now().millisecondsSinceEpoch,
          ...state,
        },
      ],
    );
    await SessionResumeService.saveRouteLocation(normalizedParentRoute);
    unawaited(RestorationCoordinator.instance.flush());
  }

  static Future<void> _clearDetachedCalendarOverlayState(String kind) async {
    if (RestorationCoordinator
        .instance
        .shouldPreserveOverlayForLifecycleClose) {
      return;
    }
    final stack = await RestorationCoordinator.instance.readOverlayStack();
    final next = stack
        .where((entry) => entry['kind'] != kind)
        .toList(growable: false);
    await RestorationCoordinator.instance.saveOverlayStack(next);
  }

  static Future<void> showActionsMenuFromAnyContext(
    BuildContext context, {
    bool includeNewNote = true,
    void Function(String location)? onNavigate,
  }) async {
    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      await mountedHost.showActionsMenuFromOutside(
        context,
        includeNewNote: includeNewNote,
      );
      return;
    }
    await _showDetachedActionsMenu(
      context,
      includeNewNote: includeNewNote,
      onNavigate: onNavigate,
    );
  }

  static Future<void> showDetachedActionsMenuFromAnyContext(
    BuildContext context, {
    bool includeNewNote = true,
    void Function(String location)? onNavigate,
  }) async {
    await _showDetachedActionsMenu(
      context,
      includeNewNote: includeNewNote,
      onNavigate: onNavigate,
    );
  }

  static Widget buildDetachedActionsMenuPanel(
    BuildContext context, {
    bool includeNewNote = true,
    void Function(String location)? onNavigate,
    Future<void> Function()? onOpenCalendars,
    Future<void> Function()? onOpenFlowStudio,
    Future<void> Function()? onOpenNewNote,
    required Future<void> Function() closeMenu,
  }) {
    return _CalendarActionsMenuPanel(
      actionsBuilder: (hasUnreadInbox) => _detachedCalendarActions(
        context,
        hasUnreadInbox: hasUnreadInbox,
        includeNewNote: includeNewNote,
        onNavigate: onNavigate,
        onOpenCalendars: onOpenCalendars,
        onOpenFlowStudio: onOpenFlowStudio,
        onOpenNewNote: onOpenNewNote,
      ),
      onSelected: (action) async {
        if (action.dispatchBeforeClose) {
          await action.onSelected();
          await closeMenu();
          return;
        }
        await closeMenu();
        await action.onSelected();
      },
    );
  }

  static Future<void> openQuickAddFromAnyContext(BuildContext context) async {
    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      await mountedHost.openQuickAddFromOutside();
      return;
    }
    await _openDetachedQuickAddSheet(context);
  }

  static DateTime _nextWeekdayForQuickAdd(DateTime base, int weekday) {
    final delta = (weekday - base.weekday + 7) % 7;
    final add = delta == 0 ? 7 : delta;
    return DateUtils.dateOnly(base.add(Duration(days: add)));
  }

  static QuickAddParse? parseQuickAddText(String raw) {
    final input = raw.trim();
    if (input.isEmpty) return null;

    final now = DateTime.now();
    DateTime date = DateUtils.dateOnly(now);
    bool hasDate = false;
    final lower = input.toLowerCase();
    final removals = <String>[];

    final mmdd = RegExp(
      r'(\d{1,2})/(\d{1,2})(?:/(\d{2,4}))?',
    ).firstMatch(lower);
    if (mmdd != null) {
      int m = int.parse(mmdd.group(1)!);
      int d = int.parse(mmdd.group(2)!);
      int y = mmdd.group(3) != null ? int.parse(mmdd.group(3)!) : now.year;
      if (y < 100) y += 2000;
      date = DateUtils.dateOnly(DateTime(y, m, d));
      hasDate = true;
      removals.add(mmdd.group(0)!);
    } else {
      final months = {
        'jan': 1,
        'january': 1,
        'feb': 2,
        'february': 2,
        'mar': 3,
        'march': 3,
        'apr': 4,
        'april': 4,
        'may': 5,
        'jun': 6,
        'june': 6,
        'jul': 7,
        'july': 7,
        'aug': 8,
        'august': 8,
        'sep': 9,
        'sept': 9,
        'september': 9,
        'oct': 10,
        'october': 10,
        'nov': 11,
        'november': 11,
        'dec': 12,
        'december': 12,
      };
      final monthMatch = RegExp(
        r'(jan|feb|mar|apr|may|jun|jul|aug|sep|sept|oct|nov|dec)[a-z]*\s+(\d{1,2})(?:,\s*(\d{2,4}))?',
      ).firstMatch(lower);
      if (monthMatch != null) {
        final m = months[monthMatch.group(1)!]!;
        final d = int.parse(monthMatch.group(2)!);
        int y = monthMatch.group(3) != null
            ? int.parse(monthMatch.group(3)!)
            : now.year;
        if (y < 100) y += 2000;
        date = DateUtils.dateOnly(DateTime(y, m, d));
        hasDate = true;
        removals.add(monthMatch.group(0)!);
      }
    }

    if (!hasDate) {
      if (lower.contains('today')) {
        date = DateUtils.dateOnly(now);
        hasDate = true;
        removals.add('today');
      } else if (lower.contains('tomorrow')) {
        date = DateUtils.dateOnly(now.add(const Duration(days: 1)));
        hasDate = true;
        removals.add('tomorrow');
      }

      final inDays = RegExp(r'in\s+(\d+)\s+day').firstMatch(lower);
      if (!hasDate && inDays != null) {
        final n = int.parse(inDays.group(1)!);
        date = DateUtils.dateOnly(now.add(Duration(days: n)));
        hasDate = true;
        removals.add(inDays.group(0)!);
      }

      if (!hasDate) {
        final weekdays = {
          'mon': DateTime.monday,
          'tue': DateTime.tuesday,
          'tues': DateTime.tuesday,
          'wed': DateTime.wednesday,
          'thu': DateTime.thursday,
          'thur': DateTime.thursday,
          'thurs': DateTime.thursday,
          'fri': DateTime.friday,
          'sat': DateTime.saturday,
          'sun': DateTime.sunday,
        };
        final wdMatch = RegExp(
          r'(next\s+)?(mon|tue|tues|wed|thu|thur|thurs|fri|sat|sun)',
        ).firstMatch(lower);
        if (wdMatch != null) {
          final wd = weekdays[wdMatch.group(2)!]!;
          date = _nextWeekdayForQuickAdd(now, wd);
          hasDate = true;
          removals.add(wdMatch.group(0)!);
        }
      }
    }

    if (hasDate && date.isBefore(DateUtils.dateOnly(now))) {
      date = DateUtils.dateOnly(DateTime(date.year + 1, date.month, date.day));
    }

    TimeOfDay? start;
    TimeOfDay? end;
    bool allDay = true;

    int toHour(int h, String? ap) {
      if (ap == null) return h;
      final l = ap.toLowerCase();
      if (l == 'am') {
        return h == 12 ? 0 : h;
      } else {
        return h == 12 ? 12 : h + 12;
      }
    }

    final range = RegExp(
      r'(\d{1,2})(?::(\d{2}))?\s*(am|pm)?\s*(?:-|–|to)\s*(\d{1,2})(?::(\d{2}))?\s*(am|pm)?',
      caseSensitive: false,
    ).firstMatch(lower);
    if (range != null) {
      final h1 = int.parse(range.group(1)!);
      final m1 = range.group(2) != null ? int.parse(range.group(2)!) : 0;
      final ap1 = range.group(3);
      final h2 = int.parse(range.group(4)!);
      final m2 = range.group(5) != null ? int.parse(range.group(5)!) : 0;
      final ap2 = range.group(6);
      start = TimeOfDay(hour: toHour(h1, ap1), minute: m1);
      end = TimeOfDay(hour: toHour(h2, ap2 ?? ap1), minute: m2);
      allDay = false;
      removals.add(range.group(0)!);
    } else {
      final timeMatch = RegExp(
        r'(\d{1,2})(?::(\d{2}))?\s*(am|pm)?',
        caseSensitive: false,
      ).firstMatch(lower);
      if (timeMatch != null) {
        final h = int.parse(timeMatch.group(1)!);
        final m = timeMatch.group(2) != null
            ? int.parse(timeMatch.group(2)!)
            : 0;
        final ap = timeMatch.group(3);
        start = TimeOfDay(hour: toHour(h, ap), minute: m);
        end = TimeOfDay(hour: (start.hour + 1) % 24, minute: start.minute);
        allDay = false;
        removals.add(timeMatch.group(0)!);
      }
    }

    final title = () {
      var t = input;
      for (final r in removals) {
        t = t.replaceFirst(RegExp(RegExp.escape(r), caseSensitive: false), '');
      }
      t = t.replaceAll(RegExp(r'\s+'), ' ').trim();
      return t.isEmpty ? input : t;
    }();

    return (date: date, allDay: allDay, start: start, end: end, title: title);
  }

  static Future<void> _saveDetachedQuickAddNote(QuickAddParse parsed) async {
    final k = KemeticMath.fromGregorian(parsed.date);
    final gDay = parsed.date;
    final allDay = parsed.allDay;
    final startTime = parsed.start;
    final endTime = parsed.end;
    final title = parsed.title;

    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0)
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime.minute,
          );

    final unifiedCid = EventCidUtil.buildClientEventId(
      ky: k.kYear,
      km: k.kMonth,
      kd: k.kDay,
      title: title,
      startHour: (allDay || startTime == null) ? 9 : startTime.hour,
      startMinute: (allDay || startTime == null) ? 0 : startTime.minute,
      allDay: allDay,
      flowId: -1,
    );

    final encodedDetail = _encodeDetailWithMeta(
      null,
      alertMinutes: _alertNoneMinutes,
    );

    final repo = UserEventsRepo(Supabase.instance.client);
    final endsAtUtc = (allDay || endTime == null)
        ? null
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            endTime.hour,
            endTime.minute,
          ).toUtc();

    await repo.upsertByClientId(
      clientEventId: unifiedCid,
      title: title,
      startsAtUtc: startLocal.toUtc(),
      detail: encodedDetail,
      allDay: allDay,
      endsAtUtc: endsAtUtc,
      caller: 'save_single_detached',
    );

    try {
      await repo.track(
        event: 'note_created',
        properties: {'title': title, 'all_day': allDay, 'detached': true},
        source: 'client',
      );
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DetachedQuickAdd] failed to log app_events: $e');
      }
    }
  }

  static void _routeHomeForDetachedDayEditor(BuildContext context) {
    final today = KemeticMath.fromGregorian(DateTime.now());
    _pendingDetachedSearchDay = (
      ky: today.kYear,
      km: today.kMonth,
      kd: today.kDay,
    );
    if (!context.mounted) return;
    context.go('/');
  }

  static Future<void> _openDetachedQuickAddSheet(BuildContext context) async {
    if (!context.mounted) return;
    if (_detachedQuickAddSheetOpenOrOpening) return;
    _detachedQuickAddSheetOpenOrOpening = true;

    try {
      await showModalBottomSheet<void>(
        context: context,
        useRootNavigator: true,
        isScrollControlled: true,
        backgroundColor: Colors.black,
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
        ),
        builder: (_) => _QuickAddSheet(
          parse: parseQuickAddText,
          scaffoldMessengerContext: context,
          onSave: _saveDetachedQuickAddNote,
          onOpenFullEditor: () => _routeHomeForDetachedDayEditor(context),
        ),
      );
    } finally {
      _detachedQuickAddSheetOpenOrOpening = false;
    }
  }

  static Future<void> openSearchFromAnyContext(BuildContext context) async {
    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      mountedHost._openSearchForContext(context);
      return;
    }
    final snapshot = await _loadWarmStartSearchSnapshot();
    if (!context.mounted) return;
    await _showEventSearch(
      context: context,
      notes: snapshot.notes,
      flows: snapshot.flows,
      openDay: (ky, km, kd) {
        Navigator.of(context).pop();
        _routeHomeForSearchDay(context, ky: ky, km: km, kd: kd);
      },
    );
  }

  static Future<({Map<String, List<_Note>> notes, List<_Flow> flows})>
  _loadWarmStartSearchSnapshot() async {
    final userId = Supabase.instance.client.auth.currentUser?.id.trim();
    if (userId == null || userId.isEmpty) {
      return (notes: <String, List<_Note>>{}, flows: <_Flow>[]);
    }

    try {
      final prefs = await SharedPreferences.getInstance();
      final raw = prefs.getString(
        '${CalendarPageState._kWarmStartCacheKeyPrefix}:$userId',
      );
      if (raw == null || raw.trim().isEmpty) {
        return (notes: <String, List<_Note>>{}, flows: <_Flow>[]);
      }

      final decoded = jsonDecode(raw);
      if (decoded is! Map) {
        return (notes: <String, List<_Note>>{}, flows: <_Flow>[]);
      }
      final json = Map<String, dynamic>.from(decoded);
      final snapshotUserId = (json['userId'] as String?)?.trim();
      if (snapshotUserId != null &&
          snapshotUserId.isNotEmpty &&
          snapshotUserId != userId) {
        return (notes: <String, List<_Note>>{}, flows: <_Flow>[]);
      }

      final flows = ((json['flows'] as List?) ?? const [])
          .map(_deserializeWarmStartSearchFlow)
          .whereType<_Flow>()
          .toList(growable: false);
      final notesByDay = <String, List<_Note>>{};
      final notesRaw = json['notes'];
      if (notesRaw is Map) {
        notesRaw.forEach((key, value) {
          if (value is! List) return;
          final notes = value
              .map(_deserializeWarmStartSearchNote)
              .whereType<_Note>()
              .toList(growable: false);
          if (notes.isNotEmpty) {
            notesByDay[key.toString()] = notes;
          }
        });
      }

      return (notes: notesByDay, flows: flows);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[search] warm-start cache unavailable: $e');
      }
      return (notes: <String, List<_Note>>{}, flows: <_Flow>[]);
    }
  }

  static _Flow? _deserializeWarmStartSearchFlow(Object? raw) {
    if (raw is! Map) return null;
    try {
      final json = Map<String, dynamic>.from(raw);
      final id = (json['id'] as num?)?.toInt();
      final name = json['name'] as String?;
      final colorValue = (json['color'] as num?)?.toInt();
      if (id == null || name == null || colorValue == null) return null;
      final rulesRaw = (json['rules'] as List?) ?? const [];
      final rules = <FlowRule>[];
      for (final item in rulesRaw.whereType<Map>()) {
        try {
          rules.add(CalendarPage.ruleFromJson(Map<String, dynamic>.from(item)));
        } catch (_) {
          // Ignore malformed cached rules; search still works without them.
        }
      }
      return _Flow(
        id: id,
        calendarId: json['calendarId'] as String?,
        name: name,
        color: Color(colorValue),
        active: (json['active'] as bool?) ?? true,
        isSaved: (json['isSaved'] as bool?) ?? false,
        savedAt: _parseWarmStartSearchDateTime(json['savedAt'])?.toUtc(),
        rules: rules,
        start: _parseWarmStartSearchDateTime(json['start'])?.toLocal(),
        end: _parseWarmStartSearchDateTime(json['end'])?.toLocal(),
        notes: json['notes'] as String?,
        shareId: json['shareId'] as String?,
        isHidden: (json['isHidden'] as bool?) ?? false,
        isReminder: (json['isReminder'] as bool?) ?? false,
        reminderUuid: json['reminderUuid'] as String?,
      );
    } catch (_) {
      return null;
    }
  }

  static _Note? _deserializeWarmStartSearchNote(Object? raw) {
    if (raw is! Map) return null;
    try {
      final json = Map<String, dynamic>.from(raw);
      final title = json['title'] as String?;
      final allDay = json['allDay'] as bool?;
      if (title == null || allDay == null) return null;
      final flowId = (json['flowId'] as num?)?.toInt();
      final explicitColorValue = (json['manualColor'] as num?)?.toInt();
      final resolvedColorValue = (json['resolvedColor'] as num?)?.toInt();
      final warmStartColorValue =
          explicitColorValue ??
          ((flowId != null && flowId != -1) ? resolvedColorValue : null);
      return _Note(
        id: json['id'] as String?,
        clientEventId: json['clientEventId'] as String?,
        calendarId: json['calendarId'] as String?,
        calendarName: json['calendarName'] as String?,
        title: title,
        detail: json['detail'] as String?,
        location: json['location'] as String?,
        allDay: allDay,
        start: _timeOfDayFromWarmStartMinutes(json['startMinutes']),
        end: _timeOfDayFromWarmStartMinutes(json['endMinutes']),
        flowId: flowId,
        manualColor: warmStartColorValue == null
            ? null
            : Color(warmStartColorValue),
        category: json['category'] as String?,
        isReminder: (json['isReminder'] as bool?) ?? false,
        reminderId: json['reminderId'] as String?,
        alertOffsetMinutes: (json['alertOffsetMinutes'] as num?)?.toInt(),
        actionId: json['actionId'] as String?,
        behaviorPayload: json['behaviorPayload'] is Map
            ? Map<String, dynamic>.from(json['behaviorPayload'] as Map)
            : null,
      );
    } catch (_) {
      return null;
    }
  }

  static TimeOfDay? _timeOfDayFromWarmStartMinutes(dynamic raw) {
    final totalMinutes = (raw as num?)?.toInt();
    if (totalMinutes == null || totalMinutes < 0) return null;
    return TimeOfDay(
      hour: (totalMinutes ~/ 60) % 24,
      minute: totalMinutes % 60,
    );
  }

  static DateTime? _parseWarmStartSearchDateTime(Object? raw) {
    final value = raw?.toString().trim();
    if (value == null || value.isEmpty) return null;
    return DateTime.tryParse(value);
  }

  static String _gregYearLabelForSearch(int kYear, int kMonth) {
    final lastDay = (kMonth == 13)
        ? (KemeticMath.isLeapKemeticYear(kYear) ? 6 : 5)
        : 30;
    final yStart = KemeticMath.toGregorian(kYear, kMonth, 1).year;
    final yEnd = KemeticMath.toGregorian(kYear, kMonth, lastDay).year;
    return (yStart == yEnd) ? '$yStart' : '$yStart/$yEnd';
  }

  static Future<void> _showEventSearch({
    required BuildContext context,
    required Map<String, List<_Note>> notes,
    required List<_Flow> flows,
    required void Function(int ky, int km, int kd) openDay,
  }) async {
    UiGuards.disableJournalSwipe();
    try {
      await showSearch<void>(
        context: context,
        delegate: _EventSearchDelegate(
          notes: notes,
          flows: flows,
          monthName: (km) => getMonthById(km).displayFull,
          gregYearLabelFor: _gregYearLabelForSearch,
          openDay: openDay,
        ),
      );
    } finally {
      UiGuards.enableJournalSwipe();
    }
  }

