  static void _scheduleTodayJumpAfterNavigation({
    required bool animate,
    int attempt = 0,
  }) {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final state = globalKey.currentState;
      if (state != null && state.mounted) {
        state.jumpToTodayFromOutside(animate: animate);
        return;
      }
      if (attempt >= 20) return;
      unawaited(
        Future<void>.delayed(const Duration(milliseconds: 50)).then((_) {
          _scheduleTodayJumpAfterNavigation(
            animate: animate,
            attempt: attempt + 1,
          );
        }),
      );
    });
  }

  static Future<void> _clearCalendarContinuityForTodayCommand() async {
    await RestorationCoordinator.instance.saveOverlayStack(
      const <Map<String, dynamic>>[],
    );
    final dayViewState = await AppRestorationService.instance
        .readDayViewState();
    if (dayViewState != null && dayViewState.isOpen) {
      await AppRestorationService.instance.saveDayViewState(
        dayViewState.copyWith(isOpen: false, clearEventDetail: true),
      );
    }
  }

  static void openMainCalendarAtToday(
    BuildContext context, {
    bool animate = false,
  }) {
    RestorationCoordinator.instance.suppressRestoreForUserNavigation(
      reason: 'calendar_today_command',
      surfaces: const <String>[
        RestorationCoordinator.calendarDayViewSurface,
        RestorationCoordinator.calendarOverlayStackSurface,
        RestorationCoordinator.plannerSurface,
      ],
    );
    CalendarPage._pendingDetachedLaunchAction = null;
    CalendarPage._pendingDetachedSearchDay = null;
    _mountedState?._suppressPendingRestoresForUserNavigation();
    unawaited(RestorationCoordinator.instance.recordRouteLocation('/'));
    unawaited(SessionResumeService.saveRouteLocation('/'));
    unawaited(_clearCalendarContinuityForTodayCommand());

    final router = GoRouter.of(context);
    final rootNavigator = Navigator.of(context, rootNavigator: true);
    if (rootNavigator.canPop()) {
      rootNavigator.popUntil((route) => route.isFirst);
    }
    router.go('/');
    _scheduleTodayJumpAfterNavigation(animate: animate);
  }

  // Static method for parsing rules from JSON (used by inbox import)
  static FlowRule ruleFromJson(Map<String, dynamic> j) {
    final allDay = (j['allDay'] ?? true) as bool;
    TimeOfDay? start;
    TimeOfDay? end;

    if (j['startHour'] != null && j['startMinute'] != null) {
      start = TimeOfDay(
        hour: (j['startHour'] as num).toInt(),
        minute: (j['startMinute'] as num).toInt(),
      );
    }
    if (j['endHour'] != null && j['endMinute'] != null) {
      end = TimeOfDay(
        hour: (j['endHour'] as num).toInt(),
        minute: (j['endMinute'] as num).toInt(),
      );
    }

    switch (j['type']) {
      case 'week':
        return _RuleWeek(
          weekdays: {...(j['weekdays'] as List).map((e) => (e as num).toInt())},
          allDay: allDay,
          start: start,
          end: end,
        );
      case 'decan':
        return _RuleDecan(
          months: {...(j['months'] as List).map((e) => (e as num).toInt())},
          decans: {...(j['decans'] as List).map((e) => (e as num).toInt())},
          daysInDecan: {
            ...(j['daysInDecan'] as List).map((e) => (e as num).toInt()),
          },
          allDay: allDay,
          start: start,
          end: end,
        );
      case 'dates':
        return _RuleDates(
          dates: {
            for (final n in (j['dates'] as List))
              DateUtils.dateOnly(
                DateTime.fromMillisecondsSinceEpoch((n as num).toInt()),
              ),
          },
          allDay: allDay,
          start: start,
          end: end,
        );
    }
    throw ArgumentError('Unknown rule type ${j['type']}');
  }

  // Headless persistence helper: save/delete flows + planned notes without calendar state.
  static Future<int?> _persistFlowStudioResultHeadless(
    _FlowStudioResult r,
  ) async {
    final userEventsRepo = UserEventsRepo(Supabase.instance.client);

    // Deletes
    final deleteId = r.deleteFlowId;
    if (deleteId != null) {
      await userEventsRepo.deleteByFlowId(deleteId);
      await userEventsRepo.deleteFlow(deleteId);
      _publishHeadlessCalendarInvalidation(
        reason: CalendarInvalidationReason.flowDeleted,
        flowId: deleteId,
        clientEventIds: const <String>[],
      );
      return deleteId;
    }

    // Saves
    if (r.savedFlow == null) return null;
    final f = r.savedFlow!;
    final rulesJson = jsonEncode(
      f.rules.map(CalendarPageState.ruleToJson).toList(),
    );

    final savedId = await userEventsRepo.upsertFlow(
      id: f.id > 0 ? f.id : null,
      name: f.name,
      color: f.color.toARGB32(),
      active: f.active,
      calendarId: f.calendarId,
      startDate: f.start,
      endDate: f.end,
      notes: f.notes,
      rules: rulesJson,
      isHidden: f.isHidden,
      originType: r.originType,
      originFlowId: r.originFlowId,
      originShareId: r.originShareId ?? f.shareId,
      originGenerationId: r.originGenerationId,
      rootFlowId: r.rootFlowId,
      aiMetadata: r.aiMetadata,
    );

    if (r.originGenerationId != null) {
      try {
        await userEventsRepo.flowCommit(
          generationId: r.originGenerationId!,
          flowId: savedId,
        );
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudioHeadless] flow_commit failed for generation ${r.originGenerationId}: $e',
          );
        }
      }
    }

    // Persist planned notes (with individual titles)
    final clientEventIds = <String>[];
    if (r.plannedNotes.isNotEmpty) {
      final eventFiling = EventFilingService();
      for (final p in r.plannedNotes) {
        final n = p.note;
        final gDay = KemeticMath.toGregorian(p.ky, p.km, p.kd);
        final startsAt = DateTime(
          gDay.year,
          gDay.month,
          gDay.day,
          n.start?.hour ?? 9,
          n.start?.minute ?? 0,
        );
        DateTime? endsAt;
        if (!n.allDay && n.end != null) {
          endsAt = DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            n.end!.hour,
            n.end!.minute,
          );
        } else if (!n.allDay) {
          endsAt = startsAt.add(const Duration(hours: 1));
        }

        final cid = EventCidUtil.buildClientEventId(
          ky: p.ky,
          km: p.km,
          kd: p.kd,
          title: n.title,
          startHour: n.start?.hour ?? 9,
          startMinute: n.start?.minute ?? 0,
          allDay: n.allDay,
          flowId: savedId,
        );
        clientEventIds.add(cid);

        await userEventsRepo.upsertByClientId(
          clientEventId: cid,
          title: n.title,
          startsAtUtc: startsAt.toUtc(),
          detail: (n.detail ?? '').trim().isEmpty ? null : n.detail,
          location: (n.location ?? '').trim().isEmpty ? null : n.location,
          allDay: n.allDay,
          endsAtUtc: endsAt?.toUtc(),
          calendarId: f.calendarId,
          flowLocalId: savedId,
          category: n.category,
          actionId: n.actionId,
          behaviorPayload: n.behaviorPayload,
          caller: 'flow_save_notes',
        );

        final bodyLines = <String>[
          if ((n.location ?? '').trim().isNotEmpty) n.location!.trim(),
          if ((n.detail ?? '').trim().isNotEmpty) n.detail!.trim(),
        ];
        await _fileHeadlessEventDelivery(
          eventFiling: eventFiling,
          debugLabel: 'flowStudioHeadless',
          clientEventId: cid,
          startsAtLocal: startsAt,
          alertOffsetMinutes: n.alertOffsetMinutes,
          title: n.title,
          body: bodyLines.isEmpty ? null : bodyLines.join('\n'),
        );
      }
    }

    _publishHeadlessCalendarInvalidation(
      reason: CalendarInvalidationReason.flowStudioPersisted,
      flowId: savedId,
      clientEventIds: clientEventIds,
    );
    return savedId;
  }

  static Future<int?> importFlowFromShare(
    BuildContext context,
    ImportFlowData data,
  ) async {
    final result = await showModalBottomSheet<_FlowStudioResult?>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      barrierColor: Colors.black54,
      builder: (outerCtx) {
        return DraggableScrollableSheet(
          initialChildSize: 0.8,
          minChildSize: 0.4,
          maxChildSize: 1.0,
          snap: true,
          snapSizes: const [0.8, 1.0],
          expand: false,
          builder: (_, _) {
            return ClipRRect(
              borderRadius: const BorderRadius.vertical(
                top: Radius.circular(16),
              ),
              child: Material(
                color: Colors.black,
                child: Navigator(
                  onGenerateInitialRoutes: (nav, _) => [
                    MaterialPageRoute(
                      builder: (ctx) => _FlowStudioPage(
                        existingFlows: const [],
                        importData: data,
                      ),
                    ),
                  ],
                ),
              ),
            );
          },
        );
      },
    );

    if (result != null && result.savedFlow != null) {
      final state = CalendarPage.globalKey.currentState;
      if (state != null) {
        return await state._persistFlowStudioResult(result);
      } else {
        return await CalendarPage._persistFlowStudioResultHeadless(result);
      }
    }
    return null;
  }

  static Future<int?> importGeneratedFlowFromAnyContext(
    BuildContext context, {
    required AIFlowGenerationResponse response,
    required DateTime baseStart,
  }) async {
    final data = _importDataFromAiGenerationResponse(response, baseStart);
    if (data == null) return null;
    return importFlowFromShare(context, data);
  }

  static ImportFlowData? _importDataFromAiGenerationResponse(
    AIFlowGenerationResponse response,
    DateTime baseStart,
  ) {
    try {
      final events = buildAiFlowImportEvents(response);
      if (events.isEmpty) return null;

      final now = DateTime.now();
      final share = InboxShareItem(
        shareId: 'ai-local-${now.millisecondsSinceEpoch}',
        kind: InboxShareKind.flow,
        recipientId: '',
        senderId: '',
        payloadId: 'ai-local',
        title: response.flowName ?? 'AI Flow',
        createdAt: now,
        payloadJson: {'events': events},
      );

      final cleaned = (response.flowColor ?? '#4dd0e1').replaceFirst('#', '');
      final rgb = int.tryParse(cleaned, radix: 16) ?? 0x4dd0e1;

      return ImportFlowData(
        share: share,
        name: response.flowName ?? 'AI Flow',
        color: 0xFF000000 | rgb,
        notes: response.notes,
        rules: const [],
        suggestedStartDate: baseStart,
        suggestedEndDate: response.requestedEndDate,
        overview: response.overviewSummary ?? response.overviewTitle ?? '',
        generationId: response.generationId,
        originType: 'ai',
        originFlowId: response.flowId,
        rootFlowId: response.flowId,
        aiMetadata: response.aiMetadata,
      );
    } catch (_) {
      return null;
    }
  }

