          'course_midday_minute=$kTheCourseDefaultMiddayMinute',
          'joined_ky=${joinedK.kYear}',
          'joined_km=${joinedK.kMonth}',
          'joined_kd=${joinedK.kDay}',
        ].join(';'),
      );

      final serverFlowId = await _saveNewFlow(flow);
      if (serverFlowId == null) {
        if (kDebugMode) {
          _calendarDebugPrint('[theCourse] Aborting - flow insert failed');
        }
        return -1;
      }

      final repo = UserEventsRepo(Supabase.instance.client);
      try {
        for (var i = 0; i < kTheCourseEvents.length; i++) {
          final event = kTheCourseEvents[i];
          final occurrence = occurrences[i];
          final dayOnly = DateUtils.dateOnly(occurrence.startLocal);
          final kyKmKd = KemeticMath.fromGregorian(dayOnly);
          final courseContext = courseContextForKemeticDate(
            kYear: kyKmKd.kYear,
            kMonth: kyKmKd.kMonth,
            kDay: kyKmKd.kDay,
          );
          final startTod = TimeOfDay(
            hour: occurrence.startLocal.hour,
            minute: occurrence.startLocal.minute,
          );
          final endTod = TimeOfDay(
            hour: occurrence.endLocal.hour,
            minute: occurrence.endLocal.minute,
          );
          final title = courseEventTitle(event);
          final detail = courseDetailText(
            event,
            lens: courseLens,
            context: courseContext,
          );
          final behaviorPayload = courseBehaviorPayload(
            event: event,
            schedule: occurrence,
            lens: courseLens,
            context: courseContext,
          );
          final clientEventId = _buildCid(
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            title: title,
            startHour: startTod.hour,
            startMinute: startTod.minute,
            allDay: false,
            flowId: serverFlowId,
          );
          final note = _Note(
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            title: title,
            detail: detail,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: courseActionId(event),
            behaviorPayload: behaviorPayload,
          );

          _addNote(
            kyKmKd.kYear,
            kyKmKd.kMonth,
            kyKmKd.kDay,
            title,
            detail,
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: courseActionId(event),
            behaviorPayload: behaviorPayload,
          );

          await repo.upsertByClientId(
            clientEventId: clientEventId,
            title: title,
            startsAtUtc: occurrence.startUtc,
            detail: detail,
            calendarId: _personalCalendarId,
            allDay: false,
            endsAtUtc: occurrence.endUtc,
            category: 'Ritual',
            flowLocalId: serverFlowId,
            actionId: courseActionId(event),
            behaviorPayload: behaviorPayload,
            caller: 'the_course_join',
          );

          await _scheduleAlertForEvent(
            note: note,
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            clientEventId: clientEventId,
          );
        }
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[theCourse] event creation failed: $e');
          _calendarDebugPrint('$st');
        }
        _flows.removeWhere((flow) => flow.id == serverFlowId);
        final emptyKeys = <String>[];
        _notes.forEach((key, notes) {
          notes.removeWhere((note) => note.flowId == serverFlowId);
          if (notes.isEmpty) emptyKeys.add(key);
        });
        for (final key in emptyKeys) {
          _notes.remove(key);
        }
        if (mounted) {
          setState(() {});
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Could not create The Course.')),
          );
        }
        try {
          await repo.deleteFlow(serverFlowId);
        } catch (_) {}
        return -1;
      }

      setState(() {});
      return serverFlowId;
    }

    if (startDate == null) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Please pick a start date first.')),
        );
      }
      return -1;
    }

    // 1) Build the 10 Gregorian dates starting at chosen start.
    final dates = <DateTime>{};
    DateTime firstG;
    if (useKemetic) {
      final k = KemeticMath.fromGregorian(startDate);
      // interpret startDate as selected Kemetic (already dateOnly)
      firstG = KemeticMath.toGregorian(k.kYear, k.kMonth, k.kDay);
    } else {
      firstG = DateUtils.dateOnly(startDate);
    }
    for (int i = 0; i < 10; i++) {
      dates.add(DateUtils.dateOnly(firstG.add(Duration(days: i))));
    }

    // 2) Build the flow object (RuleDates over those 10 days).
    final flow = _Flow(
      id: -1, // assigned on save
      calendarId: _personalCalendarId,
      name: template.title,
      color: template.color,
      active: true,
      rules: [
        _RuleDates(
          dates: dates,
          allDay: false,
          start: const TimeOfDay(hour: 9, minute: 0),
          end: const TimeOfDay(hour: 10, minute: 0),
        ),
      ],

      start: firstG,
      end: firstG.add(const Duration(days: 9)),
      // Encode meta so we can recognize in preview/end:
      // "mode=gregorian|kemetic; split=1; ov=...; maat=<key>"
      notes: [
        useKemetic ? 'mode=kemetic' : 'mode=gregorian',
        'split=1', // using explicit dates
        if (template.overview.trim().isNotEmpty)
          'ov=${Uri.encodeComponent(template.overview.trim())}',
        'maat=${template.key}',
      ].join(';'),
    );

    final serverFlowId = await _saveNewFlow(
      flow,
    ); // await save and get server ID
    if (serverFlowId == null) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[applyFlowTemplate] Aborting - flow insert failed',
        );
      }
      return -1;
    }

    // 3) Add 10 linked notes (title + detail from template).
    // Use 9am default; users can edit/delete individual notes later if they want.
    int dayIndex = 0;
    final ordered = dates.toList()..sort();
    for (final g in ordered) {
      final kyKmKd = KemeticMath.fromGregorian(g);
      final day = template.days[dayIndex];
      for (final slot in day.notes) {
        _addNote(
          kyKmKd.kYear,
          kyKmKd.kMonth,
          kyKmKd.kDay,
          slot.title,
          slot.detail,
          allDay: false,
          start: slot.start,
          end: slot.end,
          flowId: serverFlowId,
        );
        // sync each auto-created flow day to Supabase (fire-and-forget)
        Future.microtask(() async {
          try {
            final repo = UserEventsRepo(Supabase.instance.client);
            final scheduledAt = DateTime(
              g.year,
              g.month,
              g.day,
              slot.start.hour,
              slot.start.minute,
            );
            // Use unified clientEventId for Ma'at flows as well. The note uses
            // the provided slot start/end times; flowId identifies the
            // owning flow. This allows deletion to operate uniformly.
            final String cid = _buildCid(
              ky: kyKmKd.kYear,
              km: kyKmKd.kMonth,
              kd: kyKmKd.kDay,
              title: slot.title,
              startHour: slot.start.hour,
              startMinute: slot.start.minute,
              allDay: false,
              flowId: serverFlowId,
            );
            await repo.upsertByClientId(
              clientEventId: cid,
              title: slot.title,
              startsAtUtc: scheduledAt.toUtc(),
              detail: (slot.detail ?? '').trim().isEmpty
                  ? null
                  : slot.detail!.trim(),
              location: null,
              allDay: false,
              endsAtUtc: DateTime(
                g.year,
                g.month,
                g.day,
                slot.end.hour,
                slot.end.minute,
              ).toUtc(),
              flowLocalId: serverFlowId, // attach to the flow you just created
              caller: 'maat_autoschedule',
            );
          } catch (_) {}
        });
      }

      dayIndex++;
    }
    setState(() {});
    return serverFlowId;
  }

  /// End Flow removes the current user's local calendar copy of the flow by
  /// deleting every matched materialized row from that calendar in the
  /// canonical RPC. Previously shared, posted, or saved copies live in their
  /// own records and are not removed by this action.
  //// === FLOW LIFECYCLE: END FLOW ===
  Future<bool> _endFlowFromEventTarget(DayViewSheetEventTarget target) async {
    final flowId = target.event.flowId;
    if (flowId == null) return false;
    await _endFlow(flowId);
    return true;
  }

  Future<bool> _makeTodoFromEventTarget(DayViewSheetEventTarget target) async {
    final event = target.event;
    final flow = _calendarChromeFlowDataForId(event.flowId);
    final eventDate = KemeticMath.toGregorian(target.ky, target.km, target.kd);
    final dueDate = DateTime(eventDate.year, eventDate.month, eventDate.day);
    final dueTime = event.allDay ? null : _timeOfDayFromMinute(event.startMin);
    final source = EventTodoSource(
      title: event.title,
      detail: event.detail,
      location: event.location,
      flowName: flow?.name,
      isFlow: event.flowId != null && !event.isReminder,
      isReminder: event.isReminder,
    );
    final sourceMetadata = <String, dynamic>{
      'source': 'calendar_event_make_todo',
      'source_title': event.title,
      'source_kemetic_date': '${target.ky}-${target.km}-${target.kd}',
      if (event.id?.trim().isNotEmpty == true) 'event_id': event.id!.trim(),
      if (event.clientEventId?.trim().isNotEmpty == true)
        'client_event_id': event.clientEventId!.trim(),
      if (event.flowId != null) 'flow_id': event.flowId,
      if (flow?.name.trim().isNotEmpty == true) 'flow_name': flow!.name.trim(),
      if (event.reminderId?.trim().isNotEmpty == true)
        'reminder_id': event.reminderId!.trim(),
      if (event.isReminder) 'is_reminder': true,
    };
    final result = await makeEventTodos(
      source: source,
      dueDate: dueDate,
      dueTime: dueTime,
      metadata: sourceMetadata,
      insertTodos: _rhythmRepo.insertTodos,
    );
    if (!mounted) return false;
    if (!result.success || result.plannerLocation == null) {
      _showMakeTodoError(result.errorMessage ?? 'Could not add to-do.');
      return false;
    }
    _openPlannerTodoList(result.plannerLocation!);
    return true;
  }

  TimeOfDay _timeOfDayFromMinute(int minuteOfDay) {
    final clamped = minuteOfDay.clamp(0, 23 * 60 + 59).toInt();
    return TimeOfDay(hour: clamped ~/ 60, minute: clamped % 60);
  }

  void _showMakeTodoError(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text(message)));
  }

  void _openPlannerTodoList(String location) {
    if (!mounted) return;
    final rootNavigator = Navigator.of(context, rootNavigator: true);
    if (rootNavigator.canPop()) {
      rootNavigator.popUntil((route) => route.isFirst);
    }
    if (!mounted) return;
    context.go(location);
  }

  Future<void> _endFlow(int flowId, {DateTime? endedAtLocal}) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final effectiveEndedAtLocal = endedAtLocal ?? DateTime.now();
    if (kDebugMode) {
      _calendarDebugPrint(
        '[endFlow] flowId=$flowId endedAtLocal='
        '${effectiveEndedAtLocal.toIso8601String()}',
      );
    }

    try {
      final result = await repo.endFlow(
        flowId: flowId,
        endedAtLocal: effectiveEndedAtLocal,
        deleteAllMaterialized: true,
      );
      if (kDebugMode) {
        _calendarDebugPrint(
          '[endFlow] ✓ rpc flowId=${result.flowId} endedOn=${result.endedOn} '
          'deletedEvents=${result.deletedEventCount} '
          'retiredNotifications=${result.retiredNotificationCount} '
          'deletedCompletions=${result.deletedCompletionCount}',
        );
      }
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint('[endFlow] ✗ flowId=$flowId error=$e');
        _calendarDebugPrint('$st');
      }
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Could not end this flow right now.')),
        );
      }
      return;
    }

    // End Flow removes the local materialized calendar copy only. Shared,
    // posted, and saved copies are separate records and remain available.
    await _loadFromDisk(source: 'end_flow');
  }
  //// === END END FLOW ===

  /* ───── Day View Navigation ───── */

  void _openDayView(
    BuildContext ctx,
    int kYear,
    int kMonth,
    int kDay, {
    EventItem? focusEvent,
    int? initialFirstVisibleMinute,
    double? initialScrollOffset,
    bool? initialShowGregorian,
    EventDetailRestorationState? initialEventDetailRestorationState,
  }) {
    _restorationInteractedSinceBoot = true;
    final shouldShowDayCardRevealCoachmark =
        _shouldShowDayCardRevealCoachmarkFromOnboarding;
    final resolvedShowGregorian = initialShowGregorian ?? _showGregorian;
    final resolvedInitialFirstVisibleMinute =
        initialFirstVisibleMinute ??
        initialScrollOffset?.floor().clamp(0, 24 * 60 - 1).toInt();
    final initialDayViewState = DayViewRestorationState(
      isOpen: true,
      kYear: kYear,
      kMonth: kMonth,
      kDay: kDay,
      showGregorian: resolvedShowGregorian,
      firstVisibleMinute: resolvedInitialFirstVisibleMinute,
      scrollOffset: initialScrollOffset,
      eventDetail: initialEventDetailRestorationState,
    );
    _activeDayViewRestorationState = initialDayViewState;
    unawaited(_saveCalendarRestorationNow(reason: 'before_day_view_open'));
    unawaited(
      _persistDayViewState(initialDayViewState, reason: 'day_view_open'),
    );

    // Adapter: Convert _Note to NoteData, and prime reminders for the day
    List<NoteData> notesForDayFn(int y, int m, int d) {
      final key = '$y-$m-$d';
      final notes = _dedupeVisibleDayNotes(_notes[key] ?? const <_Note>[]);

      // Create/update local reminders for timed events on this day (Flutter-only)
      for (final n in notes) {
        if (n.isReminder) continue; // reminders manage their own schedule
        final alertLocal = _alertDateTimeLocal(
          note: n,
          kYear: y,
          kMonth: m,
          kDay: d,
        );
        if (alertLocal == null) continue;
        final alertUtc = alertLocal.toUtc();
        final rid = _reminderIdForNote(n, alertUtc);
        _reminderService.addOrUpdate(
          Reminder(
            id: rid,
            eventId: n.id?.toString(),
            title: n.title,
            detail: n.detail,
            alertAtUtc: alertUtc,
            flowId: n.flowId?.toString(),
            createdAt: DateTime.now().toUtc(),
            updatedAt: DateTime.now().toUtc(),
          ),
        );
      }

      final mapped = notes
          .map(
            (n) => NoteData(
              id: n.id?.toString(),
              clientEventId: n.clientEventId,
              calendarId: n.calendarId,
              calendarName: n.calendarName,
              title: n.title,
              detail: n.detail,
              location: n.location,
              allDay: n.allDay,
              start: n.start,
              end: n.end,
              flowId: n.flowId,
              manualColor: n.manualColor,
              category: n.category,
              isReminder: n.isReminder,
              reminderId: n.reminderId,
            ),
          )
          .toList();

      if (kDebugMode) {
        _calendarDebugPrint(
          '[DayView adapter] $y-$m-$d _Note -> NoteData count=${notes.length}',
        );
        for (int i = 0; i < notes.length; i++) {
          final n = notes[i];
          final nd = mapped[i];
          _calendarDebugPrint(
            '[DayView adapter] _Note[$i] id=${n.id} cid=${n.clientEventId} title="${n.title}"',
          );
          _calendarDebugPrint(
            '[DayView adapter] NoteData[$i] id=${nd.id} cid=${nd.clientEventId} title="${nd.title}"',
          );
        }
      }

      return mapped;
    }

    // Adapter: Convert _Flow to FlowData
    final flowIndex = _buildCalendarFlowChromeIndex();
    final activeLedgerFlowIds = _buildActiveLedgerFlowIds();

    // Get month name function
    String getMonthName(int km) => getMonthById(km).displayFull;

    // Navigate to Day View
    UiGuards.disableJournalSwipe();
    Navigator.push(
      ctx,
      MaterialPageRoute(
        builder: (context) => DayViewPage(
          initialKy: kYear,
          initialKm: kMonth,
          initialKd: kDay,
          showGregorian: resolvedShowGregorian,
          notesForDay: notesForDayFn,
          flowIndex: flowIndex,
          flowIndexBuilder: _buildCalendarFlowChromeIndex,
          activeLedgerFlowIds: activeLedgerFlowIds,
          activeLedgerFlowIdsBuilder: _buildActiveLedgerFlowIds,
          dataVersion: _dayViewDataVersion,
          getMonthName: getMonthName,
          initialFirstVisibleMinute: resolvedInitialFirstVisibleMinute,
          initialScrollOffset: initialScrollOffset,
          focusStartMin: focusEvent?.startMin,
          focusFlowId: focusEvent?.flowId,
          focusTitle: focusEvent?.title,
          initialEventDetailRestorationState:
              initialEventDetailRestorationState,
          onClose: () => Navigator.of(context).pop(),
          onManageFlows: (flowId) => _getMyFlowsCallback()(flowId),
          onOpenQuickAdd: (_) => _openQuickAddSheet(),
          onOpenSearch: (ctx) async => _openSearchForContext(ctx),
          onOpenProfile: (ctx) => _openProfile(ctx),
          onDeleteNote: (ky, km, kd, evt) async {
            await _deleteNoteByEvent(ky, km, kd, evt);
          },
          onEditNote: (ky, km, kd, evt) async {
            await _editNoteByEvent(ky, km, kd, evt);
          },
          onMoveEventTime: _moveEventInDayView,
          onShareNote: (evt) async {
            await _shareNoteSimple(evt);
          },
          onAddNote: (ky, km, kd) =>
              _openDaySheet(ky, km, kd, allowDateChange: true),
          onOpenAddNoteWithTime:
              (
                ky,
                km,
                kd, {
                TimeOfDay? start,
                TimeOfDay? end,
                bool allDay = false,
              }) {
                _openDaySheet(
                  ky,
                  km,
                  kd,
                  allowDateChange: true,
                  initialStartTime: start,
                  initialEndTime: end,
                  initialAllDay: allDay,
                );
              },
          onCreateTimedEvent: _handleCreateTimedEvent,
          onEndFlow: (id) => _endFlow(id),
          onEditReminder: (id) => _editReminderById(id),
          onEndReminder: (id) => _endReminderRule(id),
          onShareReminder: (evt) => _shareNoteSimple(evt),
          onAppendToJournal: (text) async {
            if (_journalInitialized) {
              await _journalController.appendToToday(text);
            }
          },
          showDayCardRevealCoachmarkForOnboarding:
              shouldShowDayCardRevealCoachmark,
          onDayCardRevealCoachmarkCompleted: shouldShowDayCardRevealCoachmark
              ? () => unawaited(
                  _handleDayCardRevealCoachmarkCompletedFromOnboarding(),
                )
              : null,
          shouldPreserveEventDetailRestorationOnClose: () =>
              RestorationCoordinator
                  .instance
                  .shouldPreserveOverlayForLifecycleClose,
          onSaveFlow: _saveFlowById,
          loadCompletedClientEventIds: _loadCompletedClientEventIds,
          onRecordCompletion:
              ({
                required String clientEventId,
                required int flowId,
                required DateTime completedOnDate,
                Map<String, dynamic>? metadata,
              }) => _recordEventCompletion(
                clientEventId: clientEventId,
                flowId: flowId,
                completedOnDate: completedOnDate,
                metadata: metadata,
              ),
          onUnrecordCompletion: _unrecordEventCompletion,
          onRestorationStateChanged:
              ({
                required int kYear,
                required int kMonth,
                required int kDay,
                required bool showGregorian,
                int? firstVisibleMinute,
                double? scrollOffset,
                EventDetailRestorationState? eventDetail,
              }) {
                final state = DayViewRestorationState(
                  isOpen: true,
                  kYear: kYear,
                  kMonth: kMonth,
                  kDay: kDay,
                  showGregorian: showGregorian,
                  firstVisibleMinute: firstVisibleMinute,
                  scrollOffset: scrollOffset,
                  eventDetail: eventDetail,
                );
                _activeDayViewRestorationState = state;
                unawaited(
                  _persistDayViewState(state, reason: 'day_view_state_changed'),
                );
              },
        ),
      ),
    ).then((_) {
      final preserveForLifecycle =
          !mounted ||
          RestorationCoordinator
              .instance
              .shouldPreserveOverlayForLifecycleClose;
      if (!preserveForLifecycle) {
        final closedState =
            (_activeDayViewRestorationState ?? initialDayViewState).copyWith(
              isOpen: false,
              clearEventDetail: true,
            );
        _activeDayViewRestorationState = closedState;
        unawaited(_persistDayViewState(closedState, reason: 'day_view_closed'));
      }
      // ✅ Save state when returning from day view
      if (mounted) {
        final ky = _lastViewKy ?? kYear;
        final km = _lastViewKm ?? kMonth;
        final kd = _lastViewKd ?? kDay;
        _saveViewState(ky, km, kd);

        if (kDebugMode) {
          _calendarDebugPrint(
            '💾 [CALENDAR] Saved state on day view close: $ky-$km-$kd',
          );
        }
      }
      UiGuards.enableJournalSwipe();
    });
  }

  /* ───── Day Sheet ───── */

  static const int _flowHydrationLookbackDays = 365; // 12 months back
  static const int _flowHydrationLookaheadDays = 540; // ~18 months ahead
  static const Duration _flowHydrationPadding = Duration(days: 14);
  static const Duration _startupVisibleHydrationLead = Duration(days: 45);
  static const Duration _startupVisibleHydrationTrail = Duration(days: 60);

  ({DateTime startUtc, DateTime endUtc}) _computeFlowHydrationWindow(
    Set<int> activeFlowIds,
    Map<int, _Flow> flowIndex,
  ) {
    final today = DateUtils.dateOnly(DateTime.now());
    DateTime? minStart;
    DateTime? maxEnd;

    for (final fid in activeFlowIds) {
      final flow = flowIndex[fid];
      if (flow == null) continue;
      final s = flow.start != null ? DateUtils.dateOnly(flow.start!) : null;
      final e = flow.end != null ? DateUtils.dateOnly(flow.end!) : null;
      if (s != null && (minStart == null || s.isBefore(minStart))) {
        minStart = s;
      }
      if (e != null && (maxEnd == null || e.isAfter(maxEnd))) {
        maxEnd = e;
      }
    }

    final startFloor = today.subtract(
      const Duration(days: _flowHydrationLookbackDays),
    );
    DateTime start = minStart == null
        ? startFloor
        : (minStart.isBefore(startFloor) ? startFloor : minStart);

    final endCeiling = today.add(
      const Duration(days: _flowHydrationLookaheadDays),
    );
    DateTime end;
    if (maxEnd == null) {
      end = endCeiling;
    } else {
      end = maxEnd.isAfter(endCeiling) ? endCeiling : maxEnd;
    }

    start = start.subtract(_flowHydrationPadding);
    end = end.add(_flowHydrationPadding);

    final exclusiveEnd = end.add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: exclusiveEnd.toUtc());
  }

  ({DateTime startUtc, DateTime endUtc}) _computeStandaloneHydrationWindow(
    List<_Flow> flows,
  ) {
    // Load a wide but bounded slice of standalone notes so we do not depend on
    // "first N" ordering. Baseline is ±_standaloneHydrationWindowYears around
    // today, widened to cover the visible flow horizon.
    final today = DateUtils.dateOnly(DateTime.now());
    final span = Duration(days: 365 * _standaloneHydrationWindowYears);

    DateTime start = today.subtract(span);
    DateTime end = today.add(span);

    for (final flow in flows) {
      final flowStart = flow.start != null
          ? DateUtils.dateOnly(flow.start!)
          : null;
      final flowEnd = flow.end != null ? DateUtils.dateOnly(flow.end!) : null;
      if (flowStart != null && flowStart.isBefore(start)) start = flowStart;
      if (flowEnd != null && flowEnd.isAfter(end)) end = flowEnd;
    }

    start = start.subtract(_standaloneHydrationPadding);
    end = end.add(_standaloneHydrationPadding);

    // Treat end as exclusive so the final day is fully included.
    final endExclusive = end.add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: endExclusive.toUtc());
  }

  ({DateTime startUtc, DateTime endUtc})
  _computeStartupVisibleHydrationWindow() {
    final targetKy = _lastViewKy ?? _today.kYear;
    final targetKm = _lastViewKm ?? _today.kMonth;
    final monthStart = DateUtils.dateOnly(
      KemeticMath.toGregorian(targetKy, targetKm, 1),
    );
    final monthEnd = DateUtils.dateOnly(
      KemeticMath.toGregorian(
        targetKy,
        targetKm,
        _maxDayForMonth(targetKy, targetKm),
      ),
    );
    final start = monthStart.subtract(_startupVisibleHydrationLead);
    final endExclusive = monthEnd
        .add(_startupVisibleHydrationTrail)
        .add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: endExclusive.toUtc());
  }

  ({DateTime startUtc, DateTime endUtc}) _clampHydrationWindowToFocus(
    ({DateTime startUtc, DateTime endUtc}) base,
    ({DateTime startUtc, DateTime endUtc}) focus,
  ) {
    final startUtc = base.startUtc.isAfter(focus.startUtc)
        ? base.startUtc
        : focus.startUtc;
    final endUtc = base.endUtc.isBefore(focus.endUtc)
        ? base.endUtc
        : focus.endUtc;
    if (!endUtc.isAfter(startUtc)) {
      return focus;
    }
    return (startUtc: startUtc, endUtc: endUtc);
  }

