                            const SizedBox(height: 12),

                            // COLOR PICKER – same look as Flow Studio
                            const GlossyText(
                              text: 'Color',
                              gradient: silverGloss,
                              style: TextStyle(
                                fontSize: 14,
                                fontWeight: FontWeight.w600,
                              ),
                            ),
                            const SizedBox(height: 8),
                            SizedBox(
                              height: 36,
                              child: ListView.builder(
                                scrollDirection: Axis.horizontal,
                                itemCount: _flowPalette.length,
                                itemBuilder: (_, i) {
                                  final selected = i == selectedColorIndex;
                                  final color = _flowPalette[i];

                                  return InkWell(
                                    onTap: () {
                                      setSheetState(() {
                                        selectedColorIndex = i;
                                      });
                                      persistDaySheetSession();
                                    },
                                    borderRadius: BorderRadius.circular(18),
                                    child: Container(
                                      width: 30,
                                      height: 30,
                                      margin: const EdgeInsets.only(right: 10),
                                      decoration: BoxDecoration(
                                        shape: BoxShape.circle,
                                        gradient: _glossFromColor(color),
                                        border: Border.all(
                                          color: selected
                                              ? _gold
                                              : Colors.white24,
                                          width: selected ? 2.0 : 1.0,
                                        ),
                                      ),
                                    ),
                                  );
                                },
                              ),
                            ),

                            const SizedBox(height: 12),
                            Align(
                              alignment: Alignment.centerRight,
                              child: ElevatedButton(
                                style: ElevatedButton.styleFrom(
                                  backgroundColor: _gold,
                                  foregroundColor: Colors.black,
                                ),
                                onPressed: () async {
                                  final t = controllerTitle.text.trim();
                                  final loc = controllerLocation.text.trim();
                                  final d = controllerDetail.text.trim();
                                  String detailForSave = d;
                                  if (initialCidMetadata.isNotEmpty) {
                                    if (editingIndex != null &&
                                        d == strippedInitialDetail) {
                                      // Preserve original metadata if the user didn't change the text.
                                      detailForSave = rawInitialDetail;
                                    } else {
                                      detailForSave = _appendCidMetadata(
                                        d,
                                        initialCidMetadata,
                                      );
                                    }
                                  }

                                  if (t.isEmpty) return;

                                  // Validate end time is after start time
                                  if (!allDay &&
                                      startTime != null &&
                                      endTime != null) {
                                    if (_toMinutes(endTime!) <=
                                        _toMinutes(startTime!)) {
                                      endTime = _addMinutes(startTime!, 60);
                                    }
                                  }

                                  final bool isRepeating =
                                      repeatOption != NoteRepeatOption.never;

                                  final selectedColor =
                                      _flowPalette[selectedColorIndex];

                                  final bucketKey = _kKey(
                                    sourceEditingKYear,
                                    sourceEditingKMonth,
                                    sourceEditingKDay,
                                  );
                                  final editIndex = editingIndex;
                                  final existingNote = editIndex != null
                                      ? (_notes[bucketKey] != null &&
                                                editIndex <
                                                    _notes[bucketKey]!.length
                                            ? _notes[bucketKey]![editIndex]
                                            : null)
                                      : null;
                                  final existingClientEventId =
                                      existingNote?.clientEventId ??
                                      (existingNote != null &&
                                              (existingNote.flowId == null ||
                                                  existingNote.flowId == -1)
                                          ? _buildCid(
                                              ky: sourceEditingKYear,
                                              km: sourceEditingKMonth,
                                              kd: sourceEditingKDay,
                                              title: existingNote.title,
                                              startHour:
                                                  existingNote.start?.hour,
                                              startMinute:
                                                  existingNote.start?.minute,
                                              allDay: existingNote.allDay,
                                              flowId: -1,
                                              calendarScopeToken:
                                                  _calendarScopeToken(
                                                    existingNote.calendarId,
                                                  ),
                                            )
                                          : null);

                                  try {
                                    ({String clientEventId, String eventId})?
                                    saveResult;
                                    var updatedExistingStandalone = false;

                                    if (selectedCalendar != null &&
                                        !selectedCalendar.canEdit) {
                                      ScaffoldMessenger.of(
                                        context,
                                      ).showSnackBar(
                                        const SnackBar(
                                          content: Text(
                                            'You can view this calendar, but you cannot edit it.',
                                          ),
                                        ),
                                      );
                                      return;
                                    }

                                    if (!isRepeating) {
                                      final canUpdateExisting =
                                          existingNote?.id != null &&
                                          ((existingNote?.flowId == null) ||
                                              existingNote?.flowId == -1);
                                      if (canUpdateExisting) {
                                        updatedExistingStandalone = true;
                                        saveResult =
                                            await _updateSingleNoteOnly(
                                              existingEventId:
                                                  existingNote!.id!,
                                              previousClientEventId:
                                                  existingClientEventId,
                                              selYear: selYear,
                                              selMonth: selMonth,
                                              selDay: selDay,
                                              title: t,
                                              detail: detailForSave.isEmpty
                                                  ? null
                                                  : detailForSave,
                                              location: loc.isEmpty
                                                  ? null
                                                  : loc,
                                              calendarId: selectedCalendarId,
                                              calendarName:
                                                  selectedCalendarLabel,
                                              allDay: allDay,
                                              startTime: startTime,
                                              endTime: endTime,
                                              color: selectedColor,
                                              category: selectedCategory,
                                              alertMinutesBefore:
                                                  alertMinutesBefore,
                                            );
                                      } else {
                                        saveResult = await _saveSingleNoteOnly(
                                          selYear: selYear,
                                          selMonth: selMonth,
                                          selDay: selDay,
                                          title: t,
                                          detail: detailForSave.isEmpty
                                              ? null
                                              : detailForSave,
                                          location: loc.isEmpty ? null : loc,
                                          calendarId: selectedCalendarId,
                                          calendarName: selectedCalendarLabel,
                                          allDay: allDay,
                                          startTime: startTime,
                                          endTime: endTime,
                                          color: selectedColor,
                                          category: selectedCategory,
                                          alertMinutesBefore:
                                              alertMinutesBefore,
                                        );
                                      }
                                    } else {
                                      // Repeating note - create hidden flow
                                      await _saveRepeatingNoteAsHiddenFlow(
                                        selYear: selYear,
                                        selMonth: selMonth,
                                        selDay: selDay,
                                        title: t,
                                        detail: detailForSave.isEmpty
                                            ? null
                                            : detailForSave,
                                        location: loc.isEmpty ? null : loc,
                                        calendarId: selectedCalendarId,
                                        calendarName: selectedCalendarLabel,
                                        allDay: allDay,
                                        startTime: startTime,
                                        endTime: endTime,
                                        repeatOption: repeatOption,
                                        customFrequency: customFrequency,
                                        customInterval: customInterval,
                                        endType: endType,
                                        endDate: endDate,
                                        endCount: endCount,
                                        color: selectedColor,
                                        category: selectedCategory,
                                        alertMinutesBefore: alertMinutesBefore,
                                      );
                                    }

                                    if (editIndex != null &&
                                        existingNote != null) {
                                      if (updatedExistingStandalone) {
                                        _removeLocalNoteOnly(
                                          sourceEditingKYear,
                                          sourceEditingKMonth,
                                          sourceEditingKDay,
                                          editIndex,
                                        );
                                      } else {
                                        final cidMatches =
                                            !isRepeating &&
                                            existingClientEventId != null &&
                                            saveResult != null &&
                                            existingClientEventId ==
                                                saveResult.clientEventId;
                                        if (cidMatches) {
                                          _removeLocalNoteOnly(
                                            sourceEditingKYear,
                                            sourceEditingKMonth,
                                            sourceEditingKDay,
                                            editIndex,
                                          );
                                        } else {
                                          await _deleteNote(
                                            sourceEditingKYear,
                                            sourceEditingKMonth,
                                            sourceEditingKDay,
                                            editIndex,
                                          );
                                        }
                                      }
                                    }
                                  } catch (e, stackTrace) {
                                    if (kDebugMode) {
                                      _calendarDebugPrint(
                                        '[SaveNote] Error saving note: $e',
                                      );
                                      _calendarDebugPrint(
                                        '[SaveNote] Stack trace: $stackTrace',
                                      );
                                    }
                                    if (mounted) {
                                      ScaffoldMessenger.of(
                                        context,
                                      ).showSnackBar(
                                        SnackBar(
                                          content: Text(
                                            'Failed to save note: $e',
                                          ),
                                          backgroundColor: Colors.red,
                                          duration: const Duration(seconds: 3),
                                        ),
                                      );
                                    }
                                    return; // Don't close sheet on error
                                  }

                                  if (!sheetCtx.mounted) return;
                                  Navigator.pop(sheetCtx);
                                },
                                child: const Text('Save'),
                              ),
                            ),
                          ],
                        ],
                      ),
                    ),
                  ),
                ),
              );
            },
          );
          return _DaySheetControllerDisposalScope(
            onDispose: disposeDaySheetControllers,
            child: daySheetContent,
          );
        },
      ).then((_) {
        sheetClosing = true;
        if (persistAsRestoration) {
          unawaited(AppRestorationService.instance.saveDaySheetState(null));
        }
        unawaited(
          SessionResumeService.clearResumeEntry(
            kind: _kSessionResumeKindDaySheet,
          ),
        );
        UiGuards.enableJournalSwipe();
      });

      _calendarDebugPrint('✅ Modal bottom sheet opened successfully');
    } catch (e, stackTrace) {
      _calendarDebugPrint('');
      _calendarDebugPrint('❌ ERROR OPENING DAY SHEET');
      _calendarDebugPrint('Error: $e');
      _calendarDebugPrint('Stack trace: $stackTrace');
      _calendarDebugPrint('');
      sheetClosing = true;
      disposeDaySheetControllers();
      if (persistAsRestoration) {
        unawaited(AppRestorationService.instance.saveDaySheetState(null));
      }
      unawaited(
        SessionResumeService.clearResumeEntry(
          kind: _kSessionResumeKindDaySheet,
        ),
      );
      UiGuards.enableJournalSwipe(); // Re-enable even on error
    }
  }

