  /* ───── UI ───── */
  bool _initOnce = false;

  Future<void> _requestStartupRun({String reason = 'queued'}) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) {
      _pendingInitialHydration = true;
      return;
    }
    _pendingInitialHydration = false;
    if (!mounted) return;
    _startOrCoalesceStartup(reason);
    if (_startupFlight != null && !(_startupFlight!.isCompleted)) {
      await _startupFlight!.future;
    }
  }

  void _startOrCoalesceStartup(String reason) {
    // Coalesce concurrent auth-driven runs; allow one rerun after the current flight.
    if (_startupFlight != null && !(_startupFlight!.isCompleted)) {
      _startupRerunRequested = true;
      _startupLastReason = reason;
      if (kDebugMode) {
        _calendarDebugPrint('[startup] coalesce request reason=$reason');
      }
      return;
    }

    final flight = Completer<void>();
    _startupFlight = flight;
    _startupLastReason = reason;
    _startupRerunRequested = false;
    if (kDebugMode) {
      _calendarDebugPrint('[startup] start reason=$reason');
    }
    () async {
      try {
        await _runStartupPipeline(reason);
      } catch (e, st) {
        _calendarDebugPrint('[startup] failed: $e');
        if (kDebugMode) {
          _calendarDebugPrint('$st');
        }
      } finally {
        flight.complete();
        _startupFlight = null;
        if (_startupRerunRequested) {
          final nextReason = 'rerun_after_${_startupLastReason ?? reason}';
          _startupRerunRequested = false;
          _startOrCoalesceStartup(nextReason);
        } else if (kDebugMode) {
          _calendarDebugPrint('[startup] end reason=$reason');
        }
      }
    }();
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();

    // ✅ Subscribe to RouteObserver FIRST (before _initOnce check)
    final route = ModalRoute.of(context);
    if (route is PageRoute && !_isSubscribed) {
      routeObserver.subscribe(this, route);
      _isSubscribed = true;
    }

    // ✅ PRESERVE existing _initOnce logic
    if (!_initOnce) {
      _initOnce = true;

      // 1) Load reminder rules + schedule their instances, then load flows/events
      final user = Supabase.instance.client.auth.currentUser;
      if (user != null) {
        if (widget.initialFlowIdToEdit == null &&
            !widget.openMyFlowsOnLaunch &&
            CalendarPage._pendingDetachedLaunchAction == null &&
            CalendarPage._pendingDetachedSearchDay == null) {
          _schedulePersistentOverlayRestore(reason: 'init-early');
        }
        _requestInitialStartupRun(reason: 'init').then((_) {
          final targetFlowId = widget.initialFlowIdToEdit;
          if (!mounted) return;
          if (targetFlowId != null) {
            _openFlowEditorDirectly(targetFlowId);
          } else if (widget.openMyFlowsOnLaunch) {
            _openMyFlowsList();
          } else if (!_schedulePendingDetachedLaunchActionIfAny()) {
            _schedulePersistentOverlayRestore(reason: 'init');
          }
        });
      } else {
        _pendingInitialHydration = true;
        if (kDebugMode) {
          _calendarDebugPrint(
            '[Calendar] Deferring initial hydrate until auth session is available',
          );
        }
      }
    } else if (widget.initialFlowIdToEdit != null) {
      // Already initialized (flows loaded), but widget has an initial flow id
      // e.g., if CalendarPage got rebuilt with a different target flow
      final targetFlowId = widget.initialFlowIdToEdit;
      if (targetFlowId != null) {
        _openFlowEditorDirectly(targetFlowId);
      }
    } else if (widget.openMyFlowsOnLaunch) {
      // If already initialized and caller requested My Flows, honor it.
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (mounted) _openMyFlowsList();
      });
    } else {
      _schedulePendingDetachedLaunchActionIfAny();
    }

    if (_pendingInitialHydration &&
        Supabase.instance.client.auth.currentUser != null) {
      _requestInitialStartupRun(reason: 'init-pending').then((_) {
        if (!mounted ||
            widget.initialFlowIdToEdit != null ||
            widget.openMyFlowsOnLaunch) {
          return;
        }
        if (!_schedulePendingDetachedLaunchActionIfAny()) {
          _schedulePersistentOverlayRestore(reason: 'init-pending');
        }
      });
    }
  }

  Future<void> _runStartupPipeline(String reason) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[startup] abort: no authenticated user reason=$reason',
        );
      }
      return;
    }
    try {
      await ShareRepo(
        Supabase.instance.client,
      ).syncAcceptedInviteCalendarImports();
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint('[startup] invite import sync failed: $e');
        _calendarDebugPrint('$st');
      }
    }
    final keepWarmStartVisible = _hasWarmStartSnapshotVisibleForCurrentUser();
    // If warm-start data is already on screen, keep it stable until the
    // backfill finishes instead of doing an intermediate visible-window swap.
    if (!keepWarmStartVisible) {
      await _loadFromDisk(source: 'startup:$reason');
    }
    await _restoreMyFlowsFilingSnapshotCache(reason: 'startup:$reason');
    if (widget.openMyFlowsOnLaunch && _myFlowsFilingSnapshotCache == null) {
      try {
        await _loadMyFlowsFilingSnapshot();
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[MyFlowsFiling] launch prefetch failed: $e');
          _calendarDebugPrint('$st');
        }
      }
    } else {
      _primeMyFlowsFilingSnapshotCache(reason: 'startup:$reason');
    }
    await _maybeLoadDecanReflectionPrompt();
    unawaited(() async {
      try {
        await _loadFromDisk(
          source: 'startup_backfill:$reason',
          preserveViewport: true,
        );
        await _syncReminderEvents(
          refreshUi: false,
          updateLocalCache: !keepWarmStartVisible,
        );
        await _persistWarmStartCacheNow(
          debugReason: 'startup_backfill_complete',
        );
        _primeMyFlowsFilingSnapshotCache(reason: 'startup_backfill:$reason');
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[startup] backfill/reminder sync failed (async): $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }());
  }

